ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?name ?linear_dimensions WHERE {
  ?a a :Airlines .
  ?p a :Planes .
  ?p p:hasAirlines ?a .
  ?a p:name ?name .
  ?p p:linear_dimensions ?linear_dimensions .
  ?p p:model ?model_f .
  FILTER(STR(?model_f) = "PlaneModel3")
} }
  component_2: { SELECT ?name ?weight_restriction WHERE {
  ?a a :Airlines .
  ?p a :Planes .
  ?p p:hasAirlines ?a .
  ?a p:name ?name .
  ?p p:weight_restriction ?weight_restriction .
  ?p p:model ?model_f .
  FILTER(STR(?model_f) = "PlaneModel3")
} }
  full: { SELECT ?name ?linear_dimensions ?weight_restriction WHERE {
  ?a a :Airlines .
  ?p a :Planes .
  ?p p:hasAirlines ?a .
  ?a p:name ?name .
  ?p p:linear_dimensions ?linear_dimensions .
  ?p p:weight_restriction ?weight_restriction .
  ?p p:model ?model_f .
  FILTER(STR(?model_f) = "PlaneModel3")
} }
}
